#nullable enable // autogenerated

using MVZ2Logic;
using MVZ2Logic.Entities;
using MVZ2Logic.Definitions;
using MVZ2Logic.Definitions;
using MVZ2Logic.Options;

namespace MVZ2.GameContent.Options
{
    [AutoOptionWidgetDefinition(LogicOptionWidgetNames.showHotkeys)]
    public class ShowHotkeysOptionsToggle : OptionToggleDefinition
    {
        public ShowHotkeysOptionsToggle(string nsp, string name) : base(nsp, name)
        {
        }
        public override bool ShouldEnable(IOptionContext context)
        {
            return !Global.Game.IsMobile();
        }
        public override bool GetValue(IOptionContext context)
        {
            return Global.Options.GetOptionBool(LogicOptionItemID.showHotkeys);
        }
        public override void OnValueChanged(IOptionContext context, bool value)
        {
            Global.Options.SetOptionBool(LogicOptionItemID.showHotkeys, value);
            Global.Options.SaveOptions();
        }
    }
}
